#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
const int N=1<<19|15,Mod=167772161,G=3,IG=55924054;int fac[N],ifac[N],n,qn,f[N],g[N],pos[N];
inline int qpow(int a,int b=Mod-2){int r(1);while(b)b&1?r=1ll*r*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
inline void Init(int n=1<<19)
{
	fac[0]=fac[1]=1;rep(1,n,i)fac[i]=1ll*fac[i-1]*i%Mod;
	ifac[n]=qpow(fac[n]);ifac[0]=ifac[1]=1;drep(n,3,i)ifac[i-1]=1ll*ifac[i]*i%Mod;
}
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
inline void NTT(int *f,int n,bool flag)
{
	for(int i=0;i<n;++i)if(i<pos[i]){int tmp=f[i];f[i]=f[pos[i]];f[pos[i]]=tmp;}
	for(int p=2;p<=n;p<<=1)
	{
		int len=p>>1,w=qpow(flag?IG:G,(Mod-1)/p);
		for(int l=0;l<n;l+=p)
		{
			int buf=1;for(int i=l;i<l+len;++i)
			{
				int tmp=1ll*buf*f[i+len]%Mod;
				UP(f[i+len]=f[i]-tmp);DN(f[i]+=tmp);
				buf=1ll*buf*w%Mod;
			}
		}
	}
	if(flag){int I=qpow(n);for(int i=0;i<n;++i)f[i]=1ll*f[i]*I%Mod;}
}
int main()
{
	scanf("%d",&qn);n=1;while(n<=qn*2)n<<=1;Init();
	rep(0,qn,i)f[i]=1ll*qpow(i,qn)*ifac[i]%Mod,g[i]=(i&1?(Mod-ifac[i]):ifac[i]);
	for(int i=0;i<n;++i)pos[i]=(pos[i>>1]>>1)|(i&1?n>>1:0);NTT(f,n,0);NTT(g,n,0);
	for(int i=0;i<n;++i)f[i]=1ll*f[i]*g[i]%Mod;NTT(f,n,1);
	rep(0,qn,i)printf("%d ",f[i]);return 0;
}
